arguments.command:
DBGFILE="/tmp/symbols/debug.elf"

# Check dynamic symbols near those addresses
echo "=== Dynamic symbols near 0x2f4b20 ==="
nm -D /tmp/symbols/debug.elf 2>/dev/null | sort | awk '
BEGIN { target = 0x2f4b20 }
/^[0-9a-f]/ { 
  addr = strtonum("0x"$1)
  if (addr <= target) { last_addr=$1; last_name=$3; last_line=$0 }
  if (addr > target && !printed) { 
    print "Before: " last_line " (offset +" sprintf("0x%x", target - strtonum("0x"last_addr)) ")"
    print "After:  " $0
    printed=1
  }
}'

echo ""
echo "=== Dynamic symbols near 0x2f4c84 ==="
nm -D /tmp/symbols/debug.elf 2>/dev/null | sort | awk '
BEGIN { target = 0x2f4c84 }
/^[0-9a-f]/ { 
  addr = strtonum("0x"$1)
  if (addr <= target) { last_addr=$1; last_name=$3; last_line=$0 }
  if (addr > target && !printed) { 
    print "Before: " last_line " (offset +" sprintf("0x%x", target - strtonum("0x"last_addr)) ")"
    print "After:  " $0
    printed=1
  }
}'

echo ""
echo "=== Also check: are these in .rodata or jump tables? ==="
readelf -S /tmp/symbols/debug.elf 2>/dev/null | awk '
/\[/ {
  name=$2; addr=$4; off=$5; size=$6
  if (name ~ /\.text|\.rodata|\.data/) {
    start = strtonum("0x"addr)
    sz = strtonum("0x"size)
    end = start + sz
    if (0x2f4b20 >= start && 0x2f4b20 < end) print "0x2f4b20 in " name " (start=0x"addr " size=0x"size")"
    if (0x2f4c84 >= start && 0x2f4c84 < end) print "0x2f4c84 in " name " (start=0x"addr " size=0x"size")"
  }
}'

