# These might be jump table entries for computed gotos in the interpreter

# Find nearest symtab symbols
echo "=== Nearest symbols to 0x2f4b20 (symtab) ==="
nm /tmp/symbols/debug.elf 2>/dev/null | sort | awk '
BEGIN { target = 0x2f4b20 }
/^[0-9a-f]/ { 
  addr = strtonum("0x"$1)
  if (addr <= target) { last=$0; last_addr=addr }
  if (addr > target && !p) { 
    printf "  <= %s (offset +0x%x)\n", last, target-last_addr
